import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";const o=JSON.parse(`{"title":"Aggiornare Fabric su Linux","description":"Una guida passo per passo su come aggiornare Fabric su Linux.","frontmatter":{"title":"Aggiornare Fabric su Linux","description":"Una guida passo per passo su come aggiornare Fabric su Linux.","authors":["IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"it_it/players/updating-fabric/linux.md","filePath":"translated/it_it/players/updating-fabric/linux.md","lastUpdated":1770561656000}`);var s={name:`it_it/players/updating-fabric/linux.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Aggiornare Fabric su Linux <a class="header-anchor" href="#h1" aria-label="Permalink to “Aggiornare Fabric su Linux”">​</a></h1><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Scarica l&#39;Installer di Fabric <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Scarica l&#39;Installer di Fabric”">​</a></h2><p>Scarica la versione <code>.jar</code> dell&#39;Installer di Fabric dal <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">sito di Fabric</a>, cliccando su <code>Download installer (Universal/.JAR)</code>.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Esegui l&#39;Installer di Fabric <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Esegui l&#39;Installer di Fabric”">​</a></h2><p>Chiudi Minecraft e il Launcher di Minecraft prima di avviare l&#39;installer.</p><p>Apri un terminale ed esegui l&#39;installer tramite Java:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">java</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -jar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fabric-installer.jar</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Una volta aperto l&#39;installer, dovresti vedere una schermata come questa:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Fabric Installer con &quot;Installa&quot; evidenziato" loading="lazy"></p><p>Assicurati che le nuove versioni del gioco e del Loader siano corrette, poi clicca <code>Installa</code> per aggiornare Fabric.</p><div class="warning custom-block"><p class="custom-block-title">IMPORTANTE</p><p>Assicurati di deselezionare <code>Crea Profilo</code> mentre esegui l&#39;installer!</p></div><h2 id="3-update-launcher-profile" tabindex="-1">3. Aggiorna il Profilo nel Launcher di Minecraft <a class="header-anchor" href="#3-update-launcher-profile" aria-label="Permalink to “3. Aggiorna il Profilo nel Launcher di Minecraft”">​</a></h2><p>Appena l&#39;installazione è completata, apri il Launcher di Minecraft. Passa poi alla scheda <code>Installazioni</code>. Trova il profilo di Fabric, e aprine la schermata di modifica:</p><p><img src="/assets/players/updating-fabric.png" alt="Aggiornare la versione del Loader di Fabric nel Launcher di Minecraft" loading="lazy"></p><p>Sostituisci la versione con la nuova versione del Loader di Fabric che hai appena installato, e premi <code>Salva</code>.</p><h2 id="4-you-re-done" tabindex="-1">4. Hai Finito! <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. Hai Finito!”">​</a></h2><p>Appena avrai completato i passaggi potrai tornare alla scheda <code>Gioca</code>, selezionare il profilo Fabric dal menu a tendina nell&#39;angolo in basso a sinistra e premere gioca!</p><p>Se incontri qualsiasi problema nel seguire questa guida, puoi chiedere aiuto nel <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Discord di Fabric</a> nel canale <code>#player-support</code>.</p>`,18)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};